   if (maybeSetupDelay(headers)) {
-    return Http::FilterHeadersStatus::Continue;
+    return Http::FilterHeadersStatus::StopIteration;
   }

   if (maybeDoAbort(headers)) {"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 462,
    "severity": "critical",
    "description": "Inverted logic for response rate limit check causes gauge leak. The condition should decrement active_faults_ when response rate limit is NOT configured (because the fault is then complete). The current code decrements only when it IS configured, which is backwards. This causes the active_faults_ gauge to become incorrect: it over-counts when rate limit is not configured, and under-counts when rate limit is configured, leading to resource tracking errors and potential gauge leaks.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
